// ================================================================
// CodeAgent Engine v3 — Smart Execution Pipeline
// ================================================================
// Pipeline: Execute → (if fail) Detect Deps → Auto-Install → Retry
//           → (if still fail) SearXNG Search → AI Fix → Retry
// Up to 3 attempts total. Returns rich debug trail.
// ================================================================

const CODEBOX_URL = 'http://192.168.1.201:8585';
const SEARXNG_URL = 'http://192.168.1.141:8888';
const OLLAMA_URL = 'http://192.168.1.110:11434';
const FIX_MODEL = 'qwen3-coder:30b';
const MAX_ATTEMPTS = 3;

const input = $input.item.json.body || $input.item.json;
const code = input.code || '';
const language = (input.language || 'python').toLowerCase();
const stdin = input.stdin || '';
const timeout = input.timeout || 60;

const debug_trail = [];
let currentCode = code;
let lastResult = null;

// ── Helper: Execute code on Codebox ──
async function executeCode(codeStr, lang, stdinStr, timeoutSec) {
  const start = Date.now();
  try {
    const resp = await fetch(`${CODEBOX_URL}/execute`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        code: codeStr,
        language: lang,
        stdin: stdinStr,
        timeout: timeoutSec,
      }),
    });
    const data = await resp.json();
    return {
      success: data.success === true || data.exit_code === 0,
      stdout: (data.stdout || '').substring(0, 5000),
      stderr: (data.stderr || '').substring(0, 3000),
      exit_code: data.exit_code ?? -1,
      compile_output: (data.compile_output || '').substring(0, 2000),
      execution_time: data.execution_time || ((Date.now() - start) / 1000),
    };
  } catch (err) {
    return {
      success: false,
      stdout: '',
      stderr: `Codebox error: ${err.message}`,
      exit_code: -1,
      compile_output: '',
      execution_time: (Date.now() - start) / 1000,
    };
  }
}

// ── Helper: Detect missing dependencies from error ──
function detectMissingDeps(stderr, compileOutput, lang) {
  const error = (stderr + ' ' + compileOutput).toLowerCase();
  const deps = [];

  // Python
  if (lang === 'python') {
    const pyMatches = error.match(/no module named ['"]?([a-z0-9_.-]+)/gi) || [];
    for (const m of pyMatches) {
      const mod = m.replace(/no module named ['"]?/i, '').replace(/['"].*/, '');
      if (mod && !['__main__', 'builtins'].includes(mod)) deps.push(`pip install ${mod}`);
    }
  }
  // Node.js
  if (['javascript', 'typescript', 'node'].includes(lang)) {
    const nodeMatches = error.match(/cannot find module ['"]([a-z0-9@/._-]+)/gi) || [];
    for (const m of nodeMatches) {
      const mod = m.replace(/cannot find module ['"]?/i, '').replace(/['"].*/, '');
      if (mod && !mod.startsWith('.') && !mod.startsWith('/')) deps.push(`npm install -g ${mod}`);
    }
  }
  // Rust
  if (lang === 'rust') {
    const rustMatches = error.match(/can't find crate.*`([a-z0-9_]+)`/gi) || [];
    for (const m of rustMatches) {
      const crate = m.match(/`([a-z0-9_]+)`/)?.[1];
      if (crate) deps.push(`cargo install ${crate}`);
    }
  }
  // C/C++ missing headers
  if (['c', 'c++', 'cpp'].includes(lang)) {
    const headerMatches = error.match(/fatal error:.*([a-z0-9_/]+\.h)/gi) || [];
    for (const m of headerMatches) {
      const header = m.match(/([a-z0-9_/]+\.h)/)?.[1];
      if (header) deps.push(`apt-get install -y lib${header.replace('.h', '')}-dev 2>/dev/null || true`);
    }
  }
  // Go
  if (lang === 'go') {
    const goMatches = error.match(/cannot find package "([^"]+)"/gi) || [];
    for (const m of goMatches) {
      const pkg = m.match(/"([^"]+)"/)?.[1];
      if (pkg && pkg.includes('/')) deps.push(`go get ${pkg}`);
    }
  }

  return deps;
}

// ── Helper: Install dependencies via Codebox shell ──
async function installDeps(commands) {
  const results = [];
  for (const cmd of commands) {
    try {
      const resp = await fetch(`${CODEBOX_URL}/command`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ command: cmd, timeout: 30 }),
      });
      const data = await resp.json();
      results.push({ command: cmd, stdout: data.stdout || '', stderr: data.stderr || '', success: !data.stderr?.includes('ERROR') });
    } catch (err) {
      results.push({ command: cmd, error: err.message, success: false });
    }
  }
  return results;
}

// ── Helper: Search SearXNG for error solutions ──
async function searchError(errorStr, lang) {
  // Clean up error for better search — remove file paths, line numbers
  const cleanError = errorStr
    .substring(0, 200)
    .replace(/\/[a-z0-9_/.]+/gi, '')
    .replace(/line \d+/gi, '')
    .replace(/\s+/g, ' ')
    .trim();

  const query = `${lang} ${cleanError}`;
  try {
    const resp = await fetch(
      `${SEARXNG_URL}/search?q=${encodeURIComponent(query)}&format=json&categories=it&engines=stackoverflow,github,duckduckgo`,
      { signal: AbortSignal.timeout(10000) }
    );
    const data = await resp.json();
    const results = (data.results || []).slice(0, 5);
    return results.map((r, i) =>
      `${i + 1}. ${r.title || 'No title'}\n   ${(r.content || '').substring(0, 400)}\n   URL: ${r.url || ''}`
    ).join('\n\n');
  } catch (err) {
    return `Search failed: ${err.message}`;
  }
}

// ── Helper: AI fix code using Ollama ──
async function aiFixCode(originalCode, errorOutput, searchResults, lang) {
  const prompt = `You are a code fixer. Fix this ${lang} code that produced an error.

CODE:
\`\`\`
${originalCode}
\`\`\`

ERROR:
\`\`\`
${errorOutput}
\`\`\`

SEARCH RESULTS:
${searchResults || 'None available'}

Rules:
- Respond with ONLY the complete fixed code
- No explanations, no markdown fences, no comments about changes
- Keep the same overall structure and intent
- Fix the specific error(s) identified
- If you can't fix it, return the original code unchanged`;

  try {
    const resp = await fetch(`${OLLAMA_URL}/api/generate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: FIX_MODEL,
        prompt: prompt,
        stream: false,
        options: { temperature: 0.1, num_predict: 4096 },
      }),
      signal: AbortSignal.timeout(120000),
    });
    const data = await resp.json();
    let fixed = (data.response || '').trim();
    // Strip markdown fences if the model added them despite instructions
    fixed = fixed.replace(/^```[a-z]*\n?/i, '').replace(/\n?```$/i, '').trim();
    // Validate: must be substantial code, not just an explanation
    if (!fixed || fixed.length < 5 || fixed.split('\n').length < originalCode.split('\n').length * 0.3) {
      return null; // AI response was garbage, don't use it
    }
    return fixed;
  } catch (err) {
    return null;
  }
}

// ── Helper: Lint check (basic static analysis) ──
function quickLintCheck(codeStr, lang) {
  const warnings = [];
  if (lang === 'python') {
    if (codeStr.includes('print ') && !codeStr.includes('print(')) {
      warnings.push('Python 3 requires print() as a function, not a statement');
    }
  }
  if (['c', 'c++', 'cpp'].includes(lang)) {
    if (!codeStr.includes('main')) {
      warnings.push('Missing main() function');
    }
  }
  if (lang === 'java') {
    if (!codeStr.includes('class ')) {
      warnings.push('Java requires a class definition');
    }
  }
  return warnings;
}

// ================================================================
// MAIN EXECUTION PIPELINE
// ================================================================

// Pre-flight: Quick lint warnings
const lintWarnings = quickLintCheck(currentCode, language);

for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
  const trailEntry = {
    attempt,
    code: currentCode.substring(0, 3000),
    action: attempt === 1 ? 'initial' : 'unknown',
  };

  // ── Execute ──
  const result = await executeCode(currentCode, language, stdin, timeout);
  lastResult = result;

  trailEntry.success = result.success;
  trailEntry.stdout = result.stdout.substring(0, 1000);
  trailEntry.stderr = result.stderr.substring(0, 1000);
  trailEntry.compile_output = result.compile_output.substring(0, 500);
  trailEntry.execution_time = result.execution_time;

  // ── Success! ──
  if (result.success) {
    debug_trail.push(trailEntry);
    break;
  }

  // ── Failed — can we fix it? ──
  if (attempt >= MAX_ATTEMPTS) {
    trailEntry.action = 'final_failure';
    debug_trail.push(trailEntry);
    break;
  }

  const errorText = result.stderr || result.compile_output || 'Unknown error';

  // ── Step A: Try auto-installing missing dependencies ──
  const missingDeps = detectMissingDeps(result.stderr, result.compile_output, language);
  if (missingDeps.length > 0 && attempt === 1) {
    trailEntry.action = 'dep_install';
    trailEntry.deps_detected = missingDeps;
    const installResults = await installDeps(missingDeps);
    trailEntry.install_results = installResults;
    debug_trail.push(trailEntry);
    // Don't change the code — just retry with deps installed
    continue;
  }

  // ── Step B: Search + AI Fix ──
  trailEntry.action = 'ai_fix';

  // Search for the error
  const searchResults = await searchError(errorText, language);
  trailEntry.search_query = `${language} ${errorText.substring(0, 100)}`;
  trailEntry.search_results_count = (searchResults.match(/^\d+\./gm) || []).length;

  // Ask AI to fix
  const fixedCode = await aiFixCode(currentCode, errorText, searchResults, language);
  if (fixedCode && fixedCode !== currentCode) {
    trailEntry.ai_fixed = true;
    trailEntry.fixed_code_preview = fixedCode.substring(0, 500);
    currentCode = fixedCode;
  } else {
    trailEntry.ai_fixed = false;
    trailEntry.ai_note = 'AI could not produce a fix';
  }

  debug_trail.push(trailEntry);
}

// ================================================================
// BUILD RESPONSE
// ================================================================

const wasFixed = debug_trail.length > 1 && lastResult?.success;
const totalTime = debug_trail.reduce((sum, t) => sum + (t.execution_time || 0), 0);

const response = {
  // Standard fields (backward compatible)
  success: lastResult?.success || false,
  stdout: lastResult?.stdout || '',
  stderr: lastResult?.stderr || '',
  exit_code: lastResult?.exit_code ?? -1,
  language: language,
  execution_time: lastResult?.execution_time || 0,
  compile_output: lastResult?.compile_output || null,

  // Engine metadata
  job_id: `engine-v3-${Date.now()}`,
  attempts: debug_trail.length,
  total_time: Math.round(totalTime * 1000) / 1000,
  was_auto_fixed: wasFixed,
  fixed_code: wasFixed ? currentCode : null,
  original_code: wasFixed ? code : null,

  // Debug trail
  debug_trail: debug_trail,

  // Lint warnings (informational)
  lint_warnings: lintWarnings.length > 0 ? lintWarnings : null,
};

return { json: response };
